def fibonacci(n):
    if n == 1 or n == 2:
        return 1
    return fibonacci(n-1) + fibonacci(n-2)

# 2、循环
def fibonacci(n):
    a, b = 1, 1
    for _ in range(n-1):
        a, b = b, a + b
    return a
