```
def isPalindrome(s):
    if len(s) <= 1:
        return True
    elif s[0] != s[-1]:
        return False
    else:
        return isPalindrome(s[1:-1])

# 测试
print(isPalindrome('abba')) # True
print(isPalindrome('abdba')) # True
print(isPalindrome('good')) # False
